  1	import * as React from "react";
  2	import {
  3	  ActionList,
  4	  ActionListItem,
  5	  Alert,
  6	  Button,
  7	  ButtonVariant,
  8	} from "@patternfly/react-core";
  9	import { DownloadIcon } from "@patternfly/react-icons";
 10	import * as cx from "classnames";
 11	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 12	import { FormFooterProps } from "./form-utils-types";
 13	
 14	import { ButtonBar } from "../button-bar";
 15	import { Shadows, useScrollShadows } from "../hooks/useScrollShadows";
 16	import { useScrollContainer } from "../hooks/useScrollContainer";
 17	
 18	const FormFooter: React.FC<FormFooterProps> = ({
 19	  handleSubmit,
 20	  handleReset,
 21	  handleCancel,
 22	  handleDownload,
 23	  submitLabel,
 24	  resetLabel,
 25	  cancelLabel,
 26	  infoTitle,
 27	  infoMessage,
 28	  isSubmitting,
 29	  errorMessage,
 30	  successMessage,
 31	  disableSubmit,
 32	  hideSubmit = false,
 33	  showAlert,
 34	  sticky,
 35	}) => {
 36	  const { t } = useNodeHealthCheckTranslation();
 37	  const [scrollContainer, footerElementRef] = useScrollContainer();
 38	  const shadowPosition = useScrollShadows(sticky ? scrollContainer : null);
 39	  return (
 40	    <div
 41	      className={cx("ocs-form-footer", {
 42	        "ocs-form-footer__sticky": sticky,
 43	        "ocs-form-footer__shadow":
 44	          sticky &&
 45	          (shadowPosition === Shadows.both ||
 46	            shadowPosition === Shadows.bottom),
 47	      })}
 48	      data-test="form-footer"
 49	      ref={footerElementRef}
 50	    >
 51	      <ButtonBar
 52	        inProgress={isSubmitting}
 53	        errorMessage={errorMessage}
 54	        successMessage={successMessage}
 55	      >
 56	        {showAlert && (
 57	          <Alert
 58	            isInline
 59	            className="co-alert"
 60	            variant="info"
 61	            title={infoTitle || t("You made changes to this page.")}
 62	          >
 63	            {infoMessage ||
 64	              t(
 65	                "Click {{submit}} to save changes or {{reset}} to cancel changes.",
 66	                {
 67	                  submit: submitLabel,
 68	                  reset: resetLabel,
 69	                }
 70	              )}
 71	          </Alert>
 72	        )}
 73	        <ActionList>
 74	          {!hideSubmit && (
 75	            <ActionListItem>
 76	              <Button
 77	                {...(handleSubmit && { onClick: handleSubmit })}
 78	                variant={ButtonVariant.primary}
 79	                isDisabled={disableSubmit}
 80	                data-test-id="submit-button"
 81	                data-test="save-changes"
 82	              >
 83	                {submitLabel || t("Save")}
 84	              </Button>
 85	            </ActionListItem>
 86	          )}
 87	          {handleReset && (
 88	            <ActionListItem>
 89	              <Button
 90	                type="button"
 91	                data-test-id="reset-button"
 92	                variant={ButtonVariant.secondary}
 93	                onClick={handleReset}
 94	              >
 95	                {resetLabel || t("Reload")}
 96	              </Button>
 97	            </ActionListItem>
 98	          )}
 99	          {handleCancel && (
100	            <ActionListItem>
101	              <Button
102	                type="button"
103	                data-test-id="cancel-button"
104	                variant={ButtonVariant.secondary}
105	                onClick={handleCancel}
106	              >
107	                {cancelLabel || t("Cancel")}
108	              </Button>
109	            </ActionListItem>
110	          )}
111	          {handleDownload && (
112	            <ActionListItem>
113	              <Button
114	                type="button"
115	                data-test-id="download-button"
116	                variant={ButtonVariant.secondary}
117	                className="pf-c-button--align-right hidden-sm hidden-xs"
118	                onClick={handleDownload}
119	                icon={<DownloadIcon />}
120	              >
121	                {t("Download")}
122	              </Button>
123	            </ActionListItem>
124	          )}
125	        </ActionList>
126	      </ButtonBar>
127	    </div>
128	  );
129	};
130	export default FormFooter;

